#### 3.2 休眠笔记识别与归档脚本

javascript
// Obsidian 插件开发 - 休眠笔记识别脚本
// 使用场景：识别90天内未被访问的笔记并建议归档

const THREE_MONTHS_MS = 90 * 24 * 60 * 60 * 1000;

async function findDormantNotes(app) {
  const now = Date.now();
  const vault = app.vault;
  const allFiles = vault.getMarkdownFiles();

  const dormantNotes = [];

  for (const file of allFiles) {
    const stat = await vault.getResourcePath(file);
    // 获取文件最后访问时间
    const lastAccessed = stat.mtime; // mtime = modified time 作为近似
    const daysSinceAccess = (now - lastAccessed) / (24 * 60 * 60 * 1000);

    if (daysSinceAccess > 90) {
      // 检查是否被其他笔记引用
      const linkedFiles = await getBacklinks(app, file.path);

      dormantNotes.push({
        path: file.path,
        title: file.basename,
        daysSinceAccess: Math.round(daysSinceAccess),
        backlinksCount: linkedFiles.length
      });
    }
  }

  // 按引用数量排序，引用多的优先保留
  dormantNotes.sort((a, b) => a.backlinksCount - b.backlinksCount);

  return dormantNotes;
}

async function getBacklinks(app, filePath) {
  const metadataCache = app.metadataCache;
  const links = metadataCache.getBacklinksForFile(filePath);
  return Object.keys(links.links || {});
}

// 使用示例
findDormantNotes(app).then(dormant => {
  console.log(`发现 ${dormant.length} 篇休眠笔记`);
  dormant.forEach(note => {
    console.log(`- ${note.title}: ${note.daysSinceAccess}天未访问, ${note.backlinksCount}个引用`);
  });
});


#### 3.3 自动标签整理脚本


javascript
// 自动为缺少标签的笔记添加标签
// 根据文件夹路径自动推断并添加默认标签


const folderTagMapping = {
  "工作/": "#工作",
  "学习/": "#学习 #课程笔记",
  "项目/": "#项目",
  "阅读/": "#阅读 #读书笔记",
  "临时/": "#临时 #待整理",
  "归档/": "#归档 #存档"
};


async function autoTagNotes(app) {
  const vault = app.vault;
  const files = vault.getMarkdownFiles();
  let taggedCount = 0;

  for (const file of files) {
    const content = await vault.read(file);

    // 检查是否已有标签
    if (content.includes("#标签") || content.match(/^\s*tags?:/m)) {
      continue; // 已有标签，跳过
    }

    // 根据文件夹推断标签
    for (const [folder, tag] of Object.entries(folderTagMapping)) {
      if (file.path.includes(folder)) {
        // 在文件顶部添加标签行
        let newContent;
        if (content.startsWith("---")) {
          // YAML front matter 格式
          newContent = content.replace(
            /^(---\n[\s\S]*?---\n)/,
            `$1tags: [${tag.replace("#", "")}]\n`
          );
        } else {
          newContent = `${tag}\n\n${content}`;
        }

        await vault.modify(file, newContent);
        taggedCount++;
        console.log(`已为 ${file.basename} 添加标签 ${tag}`);
        break;
      }
    }
  }

  return taggedCount;
}

// 执行自动标签
autoTagNotes(app).then(count => {
  new Notice(`自动标签完成，共处理 ${count} 篇笔记`);
});


