```python
// Obsidian 插件脚本 - 识别长期未访问的休眠笔记
// 功能：找出超过指定天数的笔记，建议用户进行归档处理

class DormantNoteFinder {
  constructor(app, options = {}) {
    this.app = app;
    this.daysThreshold = options.days || 90; // 默认90天
    this.vault = app.vault;
  }

  // 获取所有笔记的最后修改时间作为访问指标
  async getAllNotesWithAccessInfo() {
    const files = this.vault.getMarkdownFiles();
    const now = Date.now();
    const notesInfo = [];


    for (const file of files) {
      const stat = await this.vault.getResourcePath(file);
      const mtime = stat.mtime; // 修改时间
      const daysSinceAccess = (now - mtime) / (1000 * 60 * 60 * 24);

      notesInfo.push({
        path: file.path,
        title: file.basename,
        folder: file.parent?.path || '/',
        lastModified: new Date(mtime).toISOString().split('T')[0],
        daysSinceAccess: Math.round(daysSinceAccess),
        isDormant: daysSinceAccess > this.daysThreshold
      });
    }

    return notesInfo;
  }

  // 筛选休眠笔记
  async findDormantNotes() {
    const allNotes = await this.getAllNotesWithAccessInfo();
    return allNotes.filter(note => note.isDormant);
  }

  // 获取笔记的引用数量
  async getBacklinksCount(filePath) {
    const metadataCache = this.app.metadataCache;
    const links = metadataCache.getBacklinksForFile(filePath);
    return Object.keys(links.links || {}).length;
  }

  // 生成休眠笔记报告
  async generateReport() {
    const dormantNotes = await this.findDormantNotes();

    // 添加引用信息
    for (const note of dormantNotes) {
      note.backlinks = await this.getBacklinksCount(note.path);
    }

    // 按引用数排序：低引用优先考虑归档
    dormantNotes.sort((a, b) => a.backlinks - b.backlinks);

    return {
      totalDormant: dormantNotes.length,
      recommendations: {
        safeToArchive: dormantNotes.filter(n => n.backlinks === 0).length,
        keepWithCare: dormantNotes.filter(n => n.backlinks > 0).length
      },
      notes: dormantNotes
    };
  }

  // 建议归档的笔记（无引用且超过阈值）
  async suggestArchive() {
    const report = await this.generateReport();
    return report.notes.filter(note => note.backlinks === 0);
  }
}

// 使用示例
const finder = new DormantNoteFinder(app, { days: 90 });
const report = await finder.generateReport();

console.log(`发现 ${report.totalDormant} 篇休眠笔记`);
console.log(`其中 ${report.recommendations.safeToArchive} 篇可以安全归档`);

// 显示前10篇需要关注的休眠笔记
report.notes.slice(0, 10).forEach(note => {
  console.log(`- "${note.title}": ${note.daysSinceAccess}天未修改, ${note.backlinks}个引用`);
});

```

### 示例 3

```python
// Obsidian 自动维护脚本 - 定期清理和整理
// 功能：自动将旧笔记移入归档文件夹，保持系统整洁

class ObsidianAutoMaintenance {
  constructor(app) {
    this.app = app;
    this.vault = app.vault;
    this.archiveFolder = '6-归档';
    this.tempFolder = '0-临时';
  }

  // 创建必要的文件夹结构
  async ensureFolders() {
    const folders = [this.archiveFolder, this.tempFolder];
    for (const folder of folders) {
      const exist = this.vault.getAbstractFileByPath(folder);
      if (!exist) {
        await this.vault.createFolder(folder);
        console.log(`创建文件夹: ${folder}`);
      }
    }
  }

  // 归档超过180天未修改且无引用的笔记
  async archiveOldNotes(daysThreshold = 180) {
    const now = Date.now();
    const threshold = daysThreshold * 24 * 60 * 60 * 1000;
    const files = this.vault.getMarkdownFiles();
    let archivedCount = 0;


    for (const file of files) {
      // 跳过特殊文件夹
      if (file.path.includes(this.archiveFolder) || 
          file.path.includes(this.tempFolder)) {
        continue;
      }

      const stat = await this.vault.getResourcePath(file);
      const age = now - stat.mtime;


      // 检查是否超过阈值
      if (age > threshold) {
        // 检查是否有引用
        const backlinks = await this.getBacklinksCount(file.path);

        if (backlinks === 0) {
          // 移动到归档文件夹
          const newPath = file.path.replace(
            file.parent?.path || '', 
            this.archiveFolder
          );
          await this.vault.rename(file, newPath);
          archivedCount++;
          console.log(`归档: ${file.basename}`);
        }
      }
    }

    return archivedCount;
  }

  // 获取引用数量
  async getBacklinksCount(filePath) {
    const links = this.app.metadataCache.getBacklinksForFile(filePath);
    return Object.keys(links.links || {}).length;
  }

  // 清理临时文件夹中的空笔记
  async cleanTempFolder() {
    const tempFolder = this.app.vault.getAbstractFileByPath(this.tempFolder);
    if (!tempFolder) return 0;

    const files = tempFolder.children || [];
    let cleanedCount = 0;

    for (const file of files) {
      if (file instanceof this.app.vault.constructor.SupportedFileTypes) {
        const content = await this.app.vault.read(file);
        // 如果笔记内容少于50字符，视为空笔记
        if (content.trim().length < 50) {
          await this.app.vault.delete(file);
          cleanedCount++;
          console.log(`删除空笔记: ${file.basename}`);
        }
      }
    }

    return cleanedCount;
  }

  // 运行完整的维护流程
  async runMaintenance() {
    console.log('开始系统维护...');

    await this.ensureFolders();

    const archived = await this.archiveOldNotes(180);
    console.log(`归档了 ${archived} 篇旧笔记`);

    const cleaned = await this.cleanTempFolder();
    console.log(`清理了 ${cleaned} 篇空笔记`);

    console.log('维护完成！');

    return { archived, cleaned };
  }
}

// 使用方式：在 Obsidian 的社区插件或自定脚本中调用
const maintenance = new ObsidianAutoMaintenance(app);
await maintenance.runMaintenance();

// 或设置定时任务自动执行
// 注意：需要在插件设置中配置自动执行时间

```



## 常见错误

- **过度完美主义陷阱**：花费大量时间追求完美的标签系统、笔记格式或文件夹结构，结果导致系统无法实际使用。正确做法是先建立基本可用的系统，然后逐步优化。
- **设置过于复杂的自动化规则**：创建大量的自动化脚本和复杂规则，虽然短期内看起来高效，但随着时间推移，这些复杂规则变得难以维护，一旦出问题就会导致整个系统瘫痪。
- **忽视定期回顾**：认为创建笔记就足够了，不需要回顾整理。但没有回顾的系统会逐渐混乱，笔记最终变得无法使用。建议即使再忙，也要保证最低限度的周回顾。
- **过度分类导致碎片化**：创建过于细致的文件夹分类（如几十个子文件夹），导致笔记被过度分散，查找困难。实际上应该更多依赖双向链接和标签来组织内容。
- **笔记归档/删除过于激进**：删除可能还有价值的笔记，或者将太多笔记直接归档导致后期难以查找。建议采用「先归档后删除」的原则，或者建立回收站机制。
- **忽视系统与使用者的同步**：随着时间推移，自己的学习目标、工作内容、生活状态都会改变，但系统却没有相应调整，导致系统不再适合自己的实际需求。


## 最佳实践

- **建立固定节奏的回顾机制**：将周回顾和月回顾设为固定的日历事件，像对待重要会议一样对待它。刚开始可以使用简单的检查清单，随着熟练度提升再逐步丰富回顾内容。
- **采用渐进式整合策略**：不要试图一次性整理所有笔记，而是每天或每周处理一小部分。可以将笔记按「紧急程度」和「重要性」分类，优先处理重要且紧急的内容。
- **设置清晰的生命周期管理**：将笔记明确分为「收集箱→工作区→永久笔记→归档区」，每个阶段都有明确的处理规则和时间限制。定期检查各区域的笔记，及时转移或清理。
- **保持系统简洁优先**：优先使用最简单的解决方案。例如，如果文件夹分类就能解决问题，就不要引入复杂的标签系统。复杂性应该随需求增长而逐步增加。
- **记录系统优化过程**：建立一个「系统演进日志」笔记，记录每次优化的原因、方法和效果。这样可以在未来回顾时理解自己的决策，也便于在出问题时有据可查。
- **定期进行用户测试**：每隔一段时间，模拟实际使用场景，如「我在找关于XX主题的所有笔记」或「我需要整理昨天的会议笔记」，检查系统能否顺畅地支持这些操作。
- **建立备份和恢复机制**：定期备份笔记库，并测试恢复流程。这样在尝试新的组织方式时可以放心大胆实验，因为知道随时可以回退到之前的状态。

