```python
# JavaScript 实现 Obsidian 风格的双向链接解析
// 用于演示如何从 Markdown 文本中提取双向链接

class ObsidianLinkParser {
    constructor() {
        this.notes = new Map();  // 存储所有笔记
        this.links = new Map();  // 存储链接关系: noteId -> [linkedNoteIds]
        this.backlinks = new Map(); // 存储反向链接
    }

    /**
     * 从 Markdown 文本中提取链接
     * 支持格式: [[笔记标题]] 或 [[笔记标题|显示文本]]
     */
    extractLinks(markdown) {
        const linkRegex = /\[\[([^\]|]+)(?:\|([^\]]+))?\]\]/g;
        const links = [];
        let match;

        while ((match = linkRegex.exec(markdown)) !== null) {
            links.push({
                target: match[1].trim(),      // 链接目标
                display: match[2] || match[1]  // 显示文本
            });
        }

        return links;
    }

    /**
     * 添加笔记并建立链接关系
     */
    addNote(noteId, title, content) {
        // 存储笔记
        this.notes.set(noteId, { id: noteId, title, content });

        // 提取链接
        const links = this.extractLinks(content);
        this.links.set(noteId, links.map(l => l.target));

        // 建立反向链接索引
        links.forEach(link => {
            if (!this.backlinks.has(link.target)) {
                this.backlinks.set(link.target, []);
            }
            this.backlinks.get(link.target).push(noteId);
        });

        console.log(`✅ 添加笔记: "${title}" (${links.length} 个链接)`);
    }

    /**
     * 获取笔记的所有反向链接
     */
    getBacklinks(noteTitle) {
        const noteIds = this.backlinks.get(noteTitle) || [];
        return noteIds.map(id => this.notes.get(id));
    }

    /**
     * 生成知识图谱数据（用于可视化）
     */
    generateGraphData() {
        const nodes = Array.from(this.notes.values()).map(note => ({
            id: note.id,
            label: note.title
        }));

        const edges = [];
        this.links.forEach((targets, sourceId) => {
            targets.forEach(target => {
                edges.push({
                    source: sourceId,
                    target: this.findNoteIdByTitle(target)
                });
            });
        });

        return { nodes, edges };
    }

    findNoteIdByTitle(title) {
        for (const [id, note] of this.notes) {
            if (note.title === title) return id;
        }
        return null;
    }
}

// 演示
const parser = new ObsidianLinkParser();

parser.addNote('1', '认知负荷', 
    '人类工作记忆容量有限，通常只能处理 5-9 个信息组块。\n\n参考: [[Zettelkasten]]'
);

parser.addNote('2', 'Zettelkasten', 
    '卢曼发明的卡片盒笔记法，核心理念是 [[原子化原则]] 和 [[双向链接]]。\n\n相关: [[认知负荷]]'
);

parser.addNote('3', '双向链接', 
    '双向链接让你可以从任意笔记查看哪些笔记引用了它。\n\n概念来源: [[Zettelkasten]]'
);

// 查询反向链接
console.log('\n📌 "Zettelkasten" 的反向链接:');
const backlinks = parser.getBacklinks('Zettelkasten');
backlinks.forEach(note => {
    console.log(`   - ${note.title}`);
});

// 生成图谱数据
console.log('\n📊 知识图谱数据:');
console.log(JSON.stringify(parser.generateGraphData(), null, 2));
```



## 常见错误

- 收藏式笔记：只收集不加工，将笔记软件变成「第二垃圾桶」
- 过度分类：花大量时间创建文件夹层级，而不是用链接组织知识
- 追求完美格式：在开始记录前花费数小时配置主题和模板
- 孤立笔记：创建的笔记从不与其他笔记建立链接，形成信息孤岛
- 忽视定期回顾：笔记创建后再也没有打开过，无法激活长期记忆
- 复制粘贴依赖：直接复制原文而不进行消化改写，无法形成真正理解
- 工具切换焦虑：不断在各种笔记软件之间迁移，从未开始真正使用


## 最佳实践

- 从最小可行系统开始：先记录起来，哪怕只是一个文件夹和每日笔记
- 遵循原子化原则：每条笔记只包含一个核心想法，便于组合和复用
- 链接优先于分类：优先为笔记建立双向链接，而非放入文件夹
- 用自己的话重写：阅读后的笔记必须用自己的语言重新表述
- 设定输入门槛：只将「对自己有用、能引发思考」的内容加入系统
- 建立回顾节奏：每天快速浏览，每周深度回顾，每月主题探索
- 输出倒逼输入：以写文章、做分享为目标来驱动知识积累
- 接受系统的不完美：第二大脑是不断演进的，不需要一步到位

