// templates/Scripts/date-helpers.js
// 自定义日期辅助函数

// 格式化相对日期（中文）
function getRelativeDate(days, format = "YYYY-MM-DD") {
  return moment().add(days, 'days').format(format);
}

// 获取本周开始日期
function getWeekStart(format = "YYYY-MM-DD") {
  return moment().startOf('week').format(format);
}

// 获取本月开始日期
function getMonthStart(format = "YYYY-MM-DD") {
  return moment().startOf('month').format(format);
}

// 获取本季度开始日期
function getQuarterStart(format = "YYYY-MM-DD") {
  return moment().startOf('quarter').format(format);
}

// 格式化时间为中文
function formatDateChinese(date, format = "MMMM Do dddd") {
  return moment(date).locale('zh-cn').format(format);
}

// 生成日期范围
function getDateRange(startDays, endDays) {
  const result = [];
  for (let i = startDays; i <= endDays; i++) {
    result.push(moment().add(i, 'days').format("YYYY-MM-DD"));
  }
  return result;
}

// 导出模块
export {
  getRelativeDate,
  getWeekStart,
  getMonthStart,
  getQuarterStart,
  formatDateChinese,
  getDateRange
};

