  { label: "方案设计", shape: "rectangle", color: "#2196f3" },
  { label: "开发实现", shape: "rectangle", color: "#ff9800" },
  { label: "测试验证", shape: "rectangle", color: "#9c27b0" },
  { label: "部署上线", shape: "rectangle", color: "#f44336" },
  { label: "结束", shape: "ellipse", color: "#4caf50" }
];

// 创建节点元素
flowNodes.forEach((node, index) => {
  const row = Math.floor(index / 3);
  const col = index % 3;
  const x = startX + col * (nodeWidth + gapX);
  const y = startY + row * (nodeHeight + gapY);

  elements.push({
    type: node.shape,
    x: x,
    y: y,
    width: nodeWidth,
    height: nodeHeight,
    label: node.label,
    backgroundColor: node.color,
    strokeColor: "#000000",
    strokeWidth: 2,
    fillStyle: "solid",
    roundness: node.shape === "ellipse" ? 100 : 5
  });
});

// 创建箭头连接
for (let i = 0; i < elements.length - 1; i++) {
  const from = elements[i];
  const to = elements[i + 1];

  elements.push({
    type: "arrow",
    x: from.x + nodeWidth,
    y: from.y + nodeHeight / 2,
    points: [
      [0, 0],
      [to.x - from.x - nodeWidth, 0]
    ],
    strokeColor: "#333",
    strokeWidth: 2,
    startArrowhead: null,
    endArrowhead: "arrow"
  });
}

// 插入到画布
api.addElements(elements);

console.log(`已创建 ${elements.length} 个元素，包括 ${flowNodes.length} 个节点和 ${flowNodes.length - 1} 个连接箭头`);


