```python
// Obsidian 自动维护脚本 - 定期清理和整理
// 功能：自动将旧笔记移入归档文件夹，保持系统整洁

class ObsidianAutoMaintenance {
  constructor(app) {
    this.app = app;
    this.vault = app.vault;
    this.archiveFolder = '6-归档';
    this.tempFolder = '0-临时';
  }

  // 创建必要的文件夹结构
  async ensureFolders() {
    const folders = [this.archiveFolder, this.tempFolder];
    for (const folder of folders) {
      const exist = this.vault.getAbstractFileByPath(folder);
      if (!exist) {
        await this.vault.createFolder(folder);
        console.log(`创建文件夹: ${folder}`);
      }
    }
  }

  // 归档超过180天未修改且无引用的笔记
  async archiveOldNotes(daysThreshold = 180) {
    const now = Date.now();
    const threshold = daysThreshold * 24 * 60 * 60 * 1000;
    const files = this.vault.getMarkdownFiles();
    let archivedCount = 0;


    for (const file of files) {
      // 跳过特殊文件夹
      if (file.path.includes(this.archiveFolder) || 
          file.path.includes(this.tempFolder)) {
        continue;
      }

      const stat = await this.vault.getResourcePath(file);
      const age = now - stat.mtime;


      // 检查是否超过阈值
      if (age > threshold) {
        // 检查是否有引用
        const backlinks = await this.getBacklinksCount(file.path);

        if (backlinks === 0) {
          // 移动到归档文件夹
          const newPath = file.path.replace(
            file.parent?.path || '', 
            this.archiveFolder
          );
          await this.vault.rename(file, newPath);
          archivedCount++;
          console.log(`归档: ${file.basename}`);
        }
      }
    }

    return archivedCount;
  }

  // 获取引用数量
  async getBacklinksCount(filePath) {
    const links = this.app.metadataCache.getBacklinksForFile(filePath);
    return Object.keys(links.links || {}).length;
  }

  // 清理临时文件夹中的空笔记
  async cleanTempFolder() {
    const tempFolder = this.app.vault.getAbstractFileByPath(this.tempFolder);
    if (!tempFolder) return 0;

    const files = tempFolder.children || [];
    let cleanedCount = 0;

    for (const file of files) {
      if (file instanceof this.app.vault.constructor.SupportedFileTypes) {
        const content = await this.app.vault.read(file);
        // 如果笔记内容少于50字符，视为空笔记
        if (content.trim().length < 50) {
          await this.app.vault.delete(file);
          cleanedCount++;
          console.log(`删除空笔记: ${file.basename}`);
        }
      }
    }

    return cleanedCount;
  }

  // 运行完整的维护流程
  async runMaintenance() {
    console.log('开始系统维护...');

    await this.ensureFolders();

    const archived = await this.archiveOldNotes(180);
    console.log(`归档了 ${archived} 篇旧笔记`);

    const cleaned = await this.cleanTempFolder();
    console.log(`清理了 ${cleaned} 篇空笔记`);

    console.log('维护完成！');

    return { archived, cleaned };
  }
}

// 使用方式：在 Obsidian 的社区插件或自定脚本中调用
const maintenance = new ObsidianAutoMaintenance(app);
await maintenance.runMaintenance();

// 或设置定时任务自动执行
// 注意：需要在插件设置中配置自动执行时间

