// Obsidian 插件脚本 - 识别长期未访问的休眠笔记
// 功能：找出超过指定天数的笔记，建议用户进行归档处理

class DormantNoteFinder {
  constructor(app, options = {}) {
    this.app = app;
    this.daysThreshold = options.days || 90; // 默认90天
    this.vault = app.vault;
  }

  // 获取所有笔记的最后修改时间作为访问指标
  async getAllNotesWithAccessInfo() {
    const files = this.vault.getMarkdownFiles();
    const now = Date.now();
    const notesInfo = [];


    for (const file of files) {
      const stat = await this.vault.getResourcePath(file);
      const mtime = stat.mtime; // 修改时间
      const daysSinceAccess = (now - mtime) / (1000 * 60 * 60 * 24);

      notesInfo.push({
        path: file.path,
        title: file.basename,
        folder: file.parent?.path || '/',
        lastModified: new Date(mtime).toISOString().split('T')[0],
        daysSinceAccess: Math.round(daysSinceAccess),
        isDormant: daysSinceAccess > this.daysThreshold
      });
    }

    return notesInfo;
  }

  // 筛选休眠笔记
  async findDormantNotes() {
    const allNotes = await this.getAllNotesWithAccessInfo();
    return allNotes.filter(note => note.isDormant);
  }

  // 获取笔记的引用数量
  async getBacklinksCount(filePath) {
    const metadataCache = this.app.metadataCache;
    const links = metadataCache.getBacklinksForFile(filePath);
    return Object.keys(links.links || {}).length;
  }

  // 生成休眠笔记报告
  async generateReport() {
    const dormantNotes = await this.findDormantNotes();

    // 添加引用信息
    for (const note of dormantNotes) {
      note.backlinks = await this.getBacklinksCount(note.path);
    }

    // 按引用数排序：低引用优先考虑归档
    dormantNotes.sort((a, b) => a.backlinks - b.backlinks);

    return {
      totalDormant: dormantNotes.length,
      recommendations: {
        safeToArchive: dormantNotes.filter(n => n.backlinks === 0).length,
        keepWithCare: dormantNotes.filter(n => n.backlinks > 0).length
      },
      notes: dormantNotes
    };
  }

  // 建议归档的笔记（无引用且超过阈值）
  async suggestArchive() {
    const report = await this.generateReport();
    return report.notes.filter(note => note.backlinks === 0);
  }
}

